import java.util.Arrays;

/**
 * Sorts an integer array in ascending order using the built-in Java method Arrays.sort().
 */
public class AscendingSorter {

    /**
     * Main function to demonstrate sorting functionality.
     *
     * @param args Command line arguments not used.
     */
    public static void main(String[] args) {
        // Define an unsorted array of integers
        int[] numbers = {5, 3, 9, 1, 7};

        // Use the Arrays.sort() method to sort the array
        Arrays.sort(numbers);

        // Print the sorted array
        System.out.println(Arrays.toString(numbers));
    }
}
```

